import React from 'react';
import './main2.css'; // assuming your CSS is saved here

const AboutMe = () => {
  return (
    <div className="about_me" id="about">
      <h2 className="heading">About Me</h2>
      <div className="about_me_info">
        <div className="about_me_left">
          <p>
            Hi! I'm Sanmathi S, a dedicated developer and enthusiastic learner currently pursuing my post-graduation in Computer Science.
            I enjoy crafting user-friendly and responsive web applications. With a strong foundation in React, JavaScript, and Python,
            I'm passionate about building meaningful tech solutions and continuously expanding my skills.
          </p>
          <p>
            Apart from coding, I actively participate in coding events, collaborate on projects, and love mentoring juniors. I aim to blend
            technical knowledge with creativity to bring ideas to life.
          </p>
        </div>
        <div className="about_me_right">
          <img 
            src="your-photo-or-illustration.png" 
            alt="About Me" 
            style={{ width: '100%', borderRadius: '10px' }}
          />
        </div>
      </div>
    </div>
  );
};

export default AboutMe;
